          language: "python",
          code: "# train_validate_sklearn\nfrom sklearn.metrics import f1_score\n\ndef train_validate_sklearn(model, X_train, y_train, X_val, y_val):\n    model.fit(X_train, y_train)\n    pred = model.predict(X_val)\n    return {\"val_f1\": f1_score(y_val, pred)}\n\n# train_epoch_torch\nimport torch\n\ndef train_epoch(model, loader, optimizer, criterion, device=\"cpu\"):\n    model.train()\n    total = 0.0\n    for x, y in loader:\n        x, y = x.to(device), y.to(device)\n        optimizer.zero_grad()\n        logits = model(x)\n        loss = criterion(logits, y)\n        loss.backward()\n        optimizer.step()\n        total += loss.item()\n    return total / max(len(loader), 1)\n\n# validate_epoch_torch\nimport torch\n\ndef validate_epoch(model, loader, criterion, device=\"cpu\"):\n    model.eval()\n    total, correct, count = 0.0, 0, 0\n    with torch.no_grad():\n        for x, y in loader:\n            x, y = x.to(device), y.to(device)\n            logits = model(x)\n            total += criterion(logits, y).item()\n            correct += (logits.argmax(1) == y).sum().item()\n            count += y.numel()\n    return {\"val_loss\": total / max(len(loader), 1), \"val_acc\": correct / max(count, 1)}\n\n# train_and_validate с history и early stopping\nimport torch\n\ndef train_epoch(model, loader, optimizer, criterion, device=\"cpu\"):\n    model.train()\n    total = 0.0\n    for x, y in loader:\n        x, y = x.to(device), y.to(device)\n        optimizer.zero_grad()\n        logits = model(x)\n        loss = criterion(logits, y)\n        loss.backward()\n        optimizer.step()\n        total += loss.item()\n    return total / max(len(loader), 1)\n\n# train_boosting_model для XGBoost/CatBoost\nimport torch\n\ndef train_epoch(model, loader, optimizer, criterion, device=\"cpu\"):\n    model.train()\n    total = 0.0\n    for x, y in loader:\n        x, y = x.to(device), y.to(device)\n        optimizer.zero_grad()\n        logits = model(x)\n        loss = criterion(logits, y)\n        loss.backward()\n        optimizer.step()\n        total += loss.item()\n    return total / max(len(loader), 1)",
